use anyhow::{anyhow, Result};

pub struct AdmissionGate;

impl AdmissionGate {
    pub fn new() -> Self {
        AdmissionGate
    }

    /// Verify that the user has valid moonshine identity/credentials
    /// This checks for:
    /// 1. ~/.moonshine.knot (signed identity file) OR
    /// 2. ~/.moonshine.json (config file) OR
    /// 3. Valid FAT_STATION mesh credentials (inference mesh membership)
    pub async fn verify_admission(&self) -> Result<()> {
        // Check for identity file (encrypted, identity-locked)
        let home = home::home_dir()
            .ok_or_else(|| anyhow!("Could not determine home directory"))?;

        let knot_path = home.join(".moonshine.knot");
        let json_path = home.join(".moonshine.json");
        let config_path = home.join(".moonshine");

        // Accept if any of these identity markers exist
        if knot_path.exists() || json_path.exists() || config_path.exists() {
            return Ok(());
        }

        // Check for mesh credentials (inference mesh membership)
        if let Ok(fat_station_port) = std::env::var("FAT_STATION_PORT") {
            // Try to reach the inference mesh on the declared port
            if self.check_mesh_health(&fat_station_port).await.is_ok() {
                return Ok(());
            }
        }

        // No valid admission found
        Err(anyhow!(
            "No moonshine identity found. Run 'moonshine init' first, or ensure FAT_STATION_PORT is set."
        ))
    }

    /// Check if the inference mesh (fat-station) is reachable
    async fn check_mesh_health(&self, port: &str) -> Result<()> {
        let url = format!("http://localhost:{}/health", port);

        let client = reqwest::Client::new();
        let response = client.get(&url).timeout(std::time::Duration::from_secs(2)).send().await?;

        if response.status().is_success() {
            Ok(())
        } else {
            Err(anyhow!("Mesh health check failed: {}", response.status()))
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_gate_creation() {
        let gate = AdmissionGate::new();
        assert_eq!(std::mem::size_of_val(&gate), 0); // Zero-sized
    }
}
